**`src/lib/preferences.ts`:**
```ts
import { createContextId } from "@builder.io/qwik";

export type Theme = "light" | "dark";
export type Locale = "en" | "es";

export const DEFAULT_THEME: Theme = "light";
export const DEFAULT_LOCALE: Locale = "en";

export const VALID_THEMES: Theme[] = ["light", "dark"];
export const VALID_LOCALES: Locale[] = ["en", "es"];

export interface Preferences {
  theme: Theme;
  locale: Locale;
}

export function resolveTheme(value: string | undefined | null): Theme {
  return value && VALID_THEMES.includes(value as Theme) ? (value as Theme) : DEFAULT_THEME;
}

export function resolveLocale(value: string | undefined | null): Locale {
  return value && VALID_LOCALES.includes(value as Locale) ? (value as Locale) : DEFAULT_LOCALE;
}

export function parseCookieHeader(cookieHeader: string | null | undefined): Record<string, string> {
  const cookies: Record<string, string> = {};
  if (!cookieHeader) return cookies;
  for (const part of cookieHeader.split(";")) {
    const idx = part.indexOf("=");
    if (idx === -1) continue;
    const key = part.slice(0, idx).trim();
    const val = part.slice(idx + 1).trim();
    cookies[key] = decodeURIComponent(val);
  }
  return cookies;
}

export function resolvePreferences(cookieHeader: string | null | undefined): Preferences {
  const cookies = parseCookieHeader(cookieHeader);
  return {
    theme: resolveTheme(cookies["theme"]),
    locale: resolveLocale(cookies["locale"]),
  };
}

export const PreferencesContext = createContextId<Preferences>("preferences");
```

